<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    overflow: hidden;
    font-family: 'Ubuntu', 'Segoe UI', system-ui, -apple-system, sans-serif;
    user-select: none;
    height: 100vh;
    width: 100vw;
  }

  #desktop {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(135deg, #2c001e 0%, #4a0033 25%, #1a1a2e 60%, #16213e 100%);
    z-index: 0;
  }

  /* Top bar */
  #topbar {
    position: fixed;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(15, 15, 15, 0.95);
    color: #e0e0e0;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    font-size: 13px;
    z-index: 1000;
    border-bottom: 1px solid rgba(255,255,255,0.08);
  }

  #topbar .left { display: flex; align-items: center; gap: 16px; }
  #topbar .right { display: flex; align-items: center; gap: 14px; }
  #topbar .app-name { font-weight: 600; letter-spacing: 0.3px; color: #e95420; }

  /* Taskbar / Dock */
  #taskbar {
    position: fixed;
    bottom: 8px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    align-items: center;
    gap: 6px;
    background: rgba(30, 30, 30, 0.85);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    padding: 6px 14px;
    border-radius: 16px;
    z-index: 999;
    border: 1px solid rgba(255,255,255,0.1);
    box-shadow: 0 8px 32px rgba(0,0,0,0.4);
  }

  #taskbar button {
    background: rgba(255,255,255,0.07);
    border: 1px solid rgba(255,255,255,0.1);
    color: #e0e0e0;
    padding: 8px 18px;
    border-radius: 10px;
    cursor: pointer;
    font-size: 13px;
    font-weight: 500;
    transition: all 0.2s ease;
    display: flex;
    align-items: center;
    gap: 6px;
  }

  #taskbar button:hover {
    background: rgba(233, 84, 32, 0.25);
    border-color: rgba(233, 84, 32, 0.5);
    color: #fff;
  }

  #taskbar button.active {
    background: rgba(233, 84, 32, 0.35);
    border-color: #e95420;
    color: #fff;
  }

  .dock-icon { font-size: 16px; }

  /* Window base */
  .app-window {
    position: absolute;
    min-width: 380px;
    min-height: 260px;
    background: #2d2d2d;
    border-radius: 12px;
    box-shadow: 0 12px 48px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.06);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }

  .app-window.hidden { display: none !important; }

  /* Window title bar */
  .win-titlebar {
    height: 38px;
    background: rgba(45, 45, 45, 0.97);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    cursor: default;
    border-bottom: 1px solid rgba(255,255,255,0.06);
    flex-shrink: 0;
  }

  .win-titlebar .title {
    color: #ccc;
    font-size: 13px;
    font-weight: 500;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .win-titlebar .title .icon { font-size: 15px; }

  .win-controls { display: flex; gap: 6px; }

  .win-btn {
    width: 24px; height: 24px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
    font-size: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    background: rgba(255,255,255,0.06);
    transition: all 0.15s ease;
  }

  .win-btn:hover { background: rgba(255,255,255,0.15); color: #fff; }
  .win-close:hover { background: #e95420 !important; color: #fff !important; }

  /* Window body */
  .win-body {
    flex: 1;
    overflow: auto;
    display: flex;
    flex-direction: column;
  }

  /* ===== FILES APP ===== */
  #files-window { top: 60px; left: 80px; width: 720px; height: 480px; }

  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 14px;
    background: rgba(50, 50, 50, 0.6);
    border-bottom: 1px solid rgba(255,255,255,0.06);
    flex-shrink: 0;
  }

  #files-up {
    background: rgba(255,255,255,0.07);
    border: 1px solid rgba(255,255,255,0.1);
    color: #ccc;
    padding: 5px 12px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 12px;
    transition: all 0.15s ease;
  }

  #files-up:hover { background: rgba(233,84,32,0.2); color: #fff; border-color: rgba(233,84,32,0.4); }
  #files-up:disabled { opacity: 0.35; cursor: default; pointer-events: none; }

  #files-path {
    flex: 1;
    background: rgba(0,0,0,0.25);
    border: 1px solid rgba(255,255,255,0.08);
    color: #e95420;
    padding: 5px 12px;
    border-radius: 6px;
    font-size: 13px;
    font-family: 'Ubuntu Mono', 'Fira Code', monospace;
    text-align: center;
    letter-spacing: 0.3px;
  }

  .files-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
  }

  .fs-item {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 8px 12px;
    border-radius: 6px;
    cursor: pointer;
    color: #ddd;
    font-size: 13.5px;
    transition: background 0.12s ease;
  }

  .fs-item:hover { background: rgba(255,255,255,0.06); }
  .fs-item.folder .fs-icon { color: #e95420; font-size: 18px; }
  .fs-item.file .fs-icon { color: #7eb8da; font-size: 18px; }

  /* ===== NOTEPAD APP ===== */
  #notepad-window { top: 80px; left: 200px; width: 640px; height: 460px; }

  .notepad-tabs-bar {
    display: flex;
    align-items: center;
    background: rgba(35, 35, 35, 0.97);
    border-bottom: 1px solid rgba(255,255,255,0.06);
    padding: 4px 8px 0;
    gap: 2px;
    flex-shrink: 0;
    overflow-x: auto;
  }

  #tabs {
    display: flex;
    align-items: flex-end;
    gap: 2px;
    flex: 1;
    min-width: 0;
  }

  .tab {
    padding: 6px 14px;
    border-radius: 8px 8px 0 0;
    cursor: pointer;
    font-size: 12.5px;
    color: #999;
    background: rgba(255,255,255,0.03);
    border: 1px solid transparent;
    border-bottom: none;
    transition: all 0.15s ease;
    white-space: nowrap;
    max-width: 160px;
    overflow: hidden;
    text-overflow: ellipsis;
    position: relative;
  }

  .tab:hover { background: rgba(255,255,255,0.07); color: #ccc; }

  .tab.active {
    background: rgba(45, 45, 45, 0.95);
    color: #fff;
    border-color: rgba(255,255,255,0.06);
    font-weight: 500;
  }

  .tab .close-tab {
    margin-left: 8px;
    font-size: 11px;
    opacity: 0;
    transition: opacity 0.12s ease;
    color: #999;
    border: none;
    background: none;
    cursor: pointer;
    padding: 0 2px;
    line-height: 1;
  }

  .tab:hover .close-tab, .tab.active .close-tab { opacity: 0.7; }
  .tab .close-tab:hover { opacity: 1 !important; color: #e95420; }

  #new-tab {
    background: rgba(255,255,255,0.06);
    border: 1px solid rgba(255,255,255,0.08);
    color: #ccc;
    width: 30px; height: 30px;
    border-radius: 7px;
    cursor: pointer;
    font-size: 16px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.15s ease;
    margin-left: 4px;
    margin-bottom: 2px;
    flex-shrink: 0;
  }

  #new-tab:hover { background: rgba(233,84,32,0.2); color: #fff; border-color: rgba(233,84,32,0.4); }

  #editor {
    flex: 1;
    width: 100%;
    background: #1e1e1e;
    color: #d4d4d4;
    border: none;
    outline: none;
    resize: none;
    padding: 16px;
    font-family: 'Ubuntu Mono', 'Fira Code', 'Consolas', monospace;
    font-size: 14px;
    line-height: 1.65;
    tab-size: 4;
  }

  #editor::placeholder { color: #555; }

  /* Scrollbar */
  ::-webkit-scrollbar { width: 8px; height: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.12); border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.2); }

  /* Dragging cursor */
  .app-window.dragging { opacity: 0.92; z-index: 9999 !important; transition: none; }
</style>
</head>
<body>

<div id="desktop">
  <!-- Top bar -->
  <div id="topbar">
    <div class="left">
      <span class="app-name">Ubuntu</span>
      <span style="color:#888;font-size:12px;">Files</span>
    </div>
    <div class="right">
      <span id="clock"></span>
    </div>
  </div>

  <!-- Taskbar / Dock -->
  <div id="taskbar">
    <button id="open-files"><span class="dock-icon">📁</span> Files</button>
    <button id="open-notepad"><span class="dock-icon">📝</span> Notepad</button>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="app-window hidden">
    <div class="win-titlebar" data-drag="true">
      <div class="title"><span class="icon">📁</span> Files</div>
      <div class="win-controls">
        <button class="win-btn win-close" title="Close">✕</button>
      </div>
    </div>
    <div class="win-body">
      <div class="files-toolbar">
        <button id="files-up">↑ Up</button>
        <span id="files-path">/</span>
      </div>
      <div class="files-list" id="files-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="app-window hidden">
    <div class="win-titlebar" data-drag="true">
      <div class="title"><span class="icon">📝</span> Notepad</div>
      <div class="win-controls">
        <button class="win-btn win-close" title="Close">✕</button>
      </div>
    </div>
    <div class="win-body">
      <div class="notepad-tabs-bar">
        <div id="tabs"></div>
        <button id="new-tab" title="New Tab">+</button>
      </div>
      <textarea id="editor" placeholder="Start typing..."></textarea>
    </div>
  </div>
</div>

<script>
(function() {
  'use strict';

  // ===== CLOCK =====
  function updateClock() {
    const now = new Date();
    document.getElementById('clock').textContent = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }
  updateClock();
  setInterval(updateClock, 10000);

  // ===== WINDOW MANAGEMENT =====
  function showWindow(id) {
    const w = document.getElementById(id);
    w.classList.remove('hidden');
    bringToFront(w);
  }

  function hideWindow(id) {
    document.getElementById(id).classList.add('hidden');
  }

  function bringToFront(el) {
    const windows = document.querySelectorAll('.app-window:not(.hidden)');
    let maxZ = 100;
    windows.forEach(w => {
      const z = parseInt(getComputedStyle(w).zIndex, 10) || 100;
      if (z >= maxZ) maxZ = z + 1;
    });
    el.style.zIndex = maxZ;
  }

  // Close buttons
  document.querySelectorAll('.win-close').forEach(btn => {
    btn.addEventListener('click', () => {
      const win = btn.closest('.app-window');
      hideWindow(win.id);
    });
  });

  // Bring to front on click
  document.querySelectorAll('.app-window').forEach(w => {
    w.addEventListener('mousedown', () => bringToFront(w));
  });

  // ===== DRAGGING =====
  document.querySelectorAll('[data-drag]').forEach(titlebar => {
    const win = titlebar.closest('.app-window');
    let startX, startY, origX, origY;

    titlebar.addEventListener('mousedown', e => {
      if (e.target.classList.contains('win-btn')) return;
      startX = e.clientX;
      startY = e.clientY;
      origX = win.offsetLeft;
      origY = win.offsetTop;
      win.classList.add('dragging');

      const onMove = ev => {
        win.style.left = (origX + ev.clientX - startX) + 'px';
        win.style.top = (origY + ev.clientY - startY) + 'px';
      };
      const onUp = () => {
        win.classList.remove('dragging');
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
      };
      document.addEventListener('mousemove', onMove);
      document.addEventListener('mouseup', onUp);
    });
  });

  // ===== LAUNCHERS =====
  document.getElementById('open-files').addEventListener('click', () => {
    showWindow('files-window');
    renderFiles();
  });

  document.getElementById('open-notepad').addEventListener('click', () => {
    showWindow('notepad-window');
    loadNotepadState();
    renderTabs();
  });

  // ===== FILESYSTEM DATA =====
  const fs = {
    '/': ['bin', 'etc', 'home', 'usr', 'var'],
    '/bin': ['bash', 'cat', 'cp', 'ls', 'mkdir', 'mv', 'rm', 'sh'],
    '/etc': ['hostname', 'hosts', 'passwd', 'fstab', 'ssh'],
    '/etc/ssh': ['sshd_config', 'ssh_host_rsa_key.pub'],
    '/home': ['user'],
    '/home/user': ['Documents', 'Downloads', 'Pictures', '.bashrc', '.profile'],
    '/home/user/Documents': ['readme.txt', 'notes.md', 'todo.org'],
    '/home/user/Downloads': ['archive.tar.gz', 'image.png'],
    '/home/user/Pictures': ['wallpaper.jpg', 'screenshot.png'],
    '/usr': ['bin', 'lib', 'share'],
    '/usr/bin': ['gcc', 'python3', 'node', 'vim'],
    '/usr/lib': ['libc.so.6', 'libssl.so'],
    '/usr/share': ['man', 'doc', 'locale'],
    '/var': ['log', 'cache', 'tmp'],
    '/var/log': ['syslog', 'auth.log', 'kern.log'],
    '/var/cache': ['apt', 'pip'],
    '/var/tmp': []
  };

  let currentPath = '/';

  function renderFiles() {
    const list = document.getElementById('files-list');
    const pathEl = document.getElementById('files-path');
    const upBtn = document.getElementById('files-up');

    pathEl.textContent = currentPath;
    upBtn.disabled = (currentPath === '/');

    const entries = fs[currentPath] || [];
    list.innerHTML = '';

    if (entries.length === 0) {
      const empty = document.createElement('div');
      empty.style.cssText = 'color:#666;font-size:13px;padding:24px;text-align:center;';
      empty.textContent = '(empty directory)';
      list.appendChild(empty);
    }

    entries.forEach(name => {
      const item = document.createElement('div');
      const fullPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
      const isFolder = fs[fullPath] !== undefined;

      item.className = 'fs-item ' + (isFolder ? 'folder' : 'file');
      item.innerHTML = '<span class="fs-icon">' + (isFolder ? '📂' : '📄') + '</span><span>' + escapeHtml(name) + '</span>';

      if (isFolder) {
        item.addEventListener('dblclick', () => {
          currentPath = fullPath;
          renderFiles();
        });
      } else {
        item.title = 'File: ' + name;
      }

      list.appendChild(item);
    });
  }

  function escapeHtml(s) {
    return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }

  document.getElementById('files-up').addEventListener('click', () => {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath = '/' + parts.join('/') || '/';
    renderFiles();
  });

  // ===== NOTEPAD STATE =====
  const STORAGE_KEY = 'notepad_state';

  function getDefaultState() {
    return [{ id: genId(), name: 'Untitled', content: '' }];
  }

  function loadNotepadState() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed) && parsed.length > 0) return parsed;
      }
    } catch(e) {}
    return getDefaultState();
  }

  function saveNotepadState() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
    } catch(e) {}
  }

  let tabs = loadNotepadState();
  let activeTabId = null;

  function genId() {
    return 'tab_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 7);
  }

  function getActiveTab() {
    return tabs.find(t => t.id === activeTabId) || null;
  }

  function renderTabs() {
    const container = document.getElementById('tabs');
    container.innerHTML = '';

    tabs.forEach(tab => {
      const el = document.createElement('div');
      el.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
      el.dataset.tabId = tab.id;

      const nameSpan = document.createElement('span');
      nameSpan.textContent = tab.name || 'Untitled';
      el.appendChild(nameSpan);

      if (tabs.length > 1) {
        const closeBtn = document.createElement('button');
        closeBtn.className = 'close-tab';
        closeBtn.textContent = '✕';
        closeBtn.addEventListener('click', e => {
          e.stopPropagation();
          closeTab(tab.id);
        });
        el.appendChild(closeBtn);
      }

      el.addEventListener('click', () => switchTab(tab.id));
      container.appendChild(el);
    });

    const active = getActiveTab();
    if (active) {
      document.getElementById('editor').value = active.content;
    } else if (tabs.length > 0) {
      // Fallback: pick first tab
      switchTab(tabs[0].id);
    }
  }

  function switchTab(id) {
    const prev = getActiveTab();
    if (prev) {
      prev.content = document.getElementById('editor').value;
      saveNotepadState();
    }
    activeTabId = id;
    renderTabs();
  }

  function closeTab(id) {
    const idx = tabs.findIndex(t => t.id === id);
    if (idx === -1) return;
    tabs.splice(idx, 1);
    saveNotepadState();
    if (activeTabId === id) {
      activeTabId = null;
      if (tabs.length > 0) {
        switchTab(tabs[Math.min(idx, tabs.length - 1)].id);
      } else {
        // Create a new tab so the editor isn't empty
        addNewTab();
      }
    } else {
      renderTabs();
    }
  }

  function addNewTab() {
    const tab = { id: genId(), name: 'Untitled', content: '' };
    tabs.push(tab);
    activeTabId = tab.id;
    saveNotepadState();
    renderTabs();
  }

  document.getElementById('new-tab').addEventListener('click', addNewTab);

  // Save on editor input (debounced)
  let saveTimeout = null;
  document.getElementById('editor').addEventListener('input', () => {
    clearTimeout(saveTimeout);
    saveTimeout = setTimeout(() => {
      const active = getActiveTab();
      if (active) {
        active.content = document.getElementById('editor').value;
        // Update tab name from first line or keep "Untitled"
        const firstLine = active.content.split('\n')[0].trim().slice(0, 30);
        if (firstLine && !active.name.startsWith('Untitled')) {
          // Don't auto-rename if user hasn't set a custom name yet
        }
        saveNotepadState();
      }
    }, 400);
  });

  // ===== INIT =====
  renderFiles();
})();
</script>
</body>
</html>
